VALUES
  ('dietitian-moex-07184', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '衛生福利部（原行政院衛生署）所公告之現行「國人膳食營養素參考攝取量」中，評估成年人葉酸需要量 的綜合性指標有數項，其中不包括下列何者？', '["血漿葉酸", "血漿同半胱胺酸", "紅血球葉酸", "紅血球同半胱胺酸"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07185', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關嬰幼兒副食品添加的種類及時間，下列何者正確？', '["副食品之給予採階段式，一般的順序為：稀釋果汁→粉狀穀類→蔬菜汁及果泥→蛋黃泥及肉泥", "嬰兒六個月以前，主要以配方奶或母乳為主，不需任何副食品添加", "嬰兒約在一歲以後才可食用魚肉豆蛋類，可避免過敏", "二歲以前的嬰幼兒，避免使用蜂蜜，可避免引發沙門氏菌之食物中毒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07186', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '懷孕第二期婦女之血液血紅素濃度會因：', '["鐵吸收率增加，而上升至平均13.5 g/dL", "鐵的吸收率下降而降低", "沒有月經週期，而上升至與成年男性相當的數值", "血漿體積增加快速，而較一般婦女為低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07187', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關嬰兒期營養的敘述，何者正確？', '["避免嬰兒發生溶血性貧血，所以維生素E建議攝取量為成人每單位體重的1.5倍", "蛋白質需要量與生長速率成正比，一般剛出生的新生兒每公斤體重需要1.8公克蛋白質", "嬰兒到6～8個月時，在胎兒期所貯存的鐵量會耗盡", "「鋅」是酵素的重要部分，嬰兒期生化代謝速度較快，故鋅需求量多"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07188', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依照「學校午餐之食物內容及營養基準」，學校午餐熱量的基準，是取各年齡階段者之男女DRIs的多少 比例？', '["1/3", "2/5", "1/3～2/5中間值", "2/5～1/2中間值"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
