  ('dietitian-moex-07193', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某餐盒業承攬學校午餐，其僱用之烹調從業人員，具有中餐烹調技術士證之持證比例應有多少？', '["50％", "60％", "70％", "80％"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
